/* ===================== Speicher ===================== */
const mem = {};
const store = {
  async get(k, s) { if (typeof window!=="undefined" && window.storage){ try{return await window.storage.get(k,s);}catch{return null;} } const key=(s?"s:":"p:")+k; return key in mem?{key,value:mem[key],shared:s}:null; },
  async set(k, v, s) { if (typeof window!=="undefined" && window.storage){ try{return await window.storage.set(k,v,s);}catch{return null;} } mem[(s?"s:":"p:")+k]=v; return {key:k,value:v,shared:s}; },
  async del(k, s) { if (typeof window!=="undefined" && window.storage){ try{return await window.storage.delete(k,s);}catch{return null;} } delete mem[(s?"s:":"p:")+k]; return {key:k,deleted:true}; },
};
async function loadJSON(k, s, fb){ const r=await store.get(k,s); if(!r) return fb; try{return JSON.parse(r.value);}catch{return fb;} }
async function saveJSON(k, v, s){ await store.set(k, JSON.stringify(v), s); }

/* ===================== Helfer ===================== */
async function sha256(t){ try{ const b=await crypto.subtle.digest("SHA-256", new TextEncoder().encode(t)); return Array.from(new Uint8Array(b)).map(x=>x.toString(16).padStart(2,"0")).join(""); }catch{ let h=5381; for(let i=0;i<t.length;i++) h=((h<<5)+h+t.charCodeAt(i))>>>0; return "fb"+h.toString(16);} }
const uid = () => Date.now().toString(36) + Math.random().toString(36).slice(2,7);
const pad = (n) => String(n).padStart(2,"0");
const iso = (d) => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
function mondayOf(d){ const x=new Date(d); const wd=(x.getDay()+6)%7; x.setDate(x.getDate()-wd); x.setHours(0,0,0,0); return x; }
function addDays(d,n){ const x=new Date(d); x.setDate(x.getDate()+n); return x; }
function todayISO(){ return iso(new Date()); }
function kw(d){ const t=new Date(Date.UTC(d.getFullYear(),d.getMonth(),d.getDate())); const day=(t.getUTCDay()+6)%7; t.setUTCDate(t.getUTCDate()-day+3); const f=new Date(Date.UTC(t.getUTCFullYear(),0,4)); return 1+Math.round(((t-f)/864e5 - 3 + ((f.getUTCDay()+6)%7))/7); }
const fmtShort = (d) => d.toLocaleDateString("de-DE",{day:"2-digit",month:"2-digit"});
const fmtLong = (iso) => new Date(iso+"T00:00:00").toLocaleDateString("de-DE",{weekday:"long",day:"numeric",month:"long"});
const surname = (n) => { if(!n) return ""; const p=n.trim().split(/\s+/); return p[p.length-1]; };
const shortAddr = (a) => a ? a.split(",")[0].trim() : "";
const blockOf = (from) => { if(!from) return -1; const h=parseInt(from.slice(0,2),10); if(h<6||h>=20) return -1; return Math.min(6, Math.floor((h-6)/2)); };
function compressImage(file, maxDim=1200, q=0.55){ return new Promise((res,rej)=>{ const r=new FileReader(); r.onload=e=>{ const img=new Image(); img.onload=()=>{ let {width:w,height:h}=img; if(w>h&&w>maxDim){h=h*maxDim/w;w=maxDim;} else if(h>maxDim){w=w*maxDim/h;h=maxDim;} const c=document.createElement("canvas"); c.width=w;c.height=h; c.getContext("2d").drawImage(img,0,0,w,h); res(c.toDataURL("image/jpeg",q)); }; img.onerror=rej; img.src=e.target.result; }; r.onerror=rej; r.readAsDataURL(file); }); }

