  async function onImportFile(file){
    if(!file) return; setImportBusy(true);
    try{
      const lc=file.name.toLowerCase(); let rows;
      if(lc.endsWith(".xlsx")||lc.endsWith(".xls")){
        try{ const XLSX=await import("xlsx"); const buf=await file.arrayBuffer(); const wb=XLSX.read(buf,{type:"array"}); const ws=wb.Sheets[wb.SheetNames[0]]; rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:""}); }
        catch(e){ setImportBusy(false); return flash("Excel konnte nicht gelesen werden – bitte in TAIFUN/Excel als CSV exportieren."); }
      } else { const text=await readFileSmart(file); rows=parseCSV(text); }
      rows=(rows||[]).filter(r=>r&&r.some(c=>String(c).trim()!==""));
      if(rows.length<2){ setImportBusy(false); return flash("Datei enthält keine Datensätze."); }
      const headers=rows[0].map(h=>String(h).trim());
      const map=importKind==="projekte"?guessMapProject(headers):guessMap(headers);
      setImportData({fileName:file.name,headers,rows:rows.slice(1),map,kind:importKind});
    }catch(e){ flash("Import fehlgeschlagen."); }
    setImportBusy(false);
    if(importRef.current) importRef.current.value="";
  }
  async function runImport(){
    const { rows, map, kind }=importData;
    const gi=(k)=>(map[k]!=null&&map[k]!=="-")?parseInt(map[k],10):-1;
    const get=(row,k)=>{ const i=gi(k); return i>=0&&i<row.length?String(row[i]).trim():""; };
    if(kind==="projekte"){
      let list=[...projects]; let added=0, updated=0;
      for(const row of rows){
        const p={ projnr:get(row,"projnr"), title:get(row,"title"), client:get(row,"client"), street:get(row,"street"), zip:get(row,"zip"), city:get(row,"city"), phone:get(row,"phone"), value:get(row,"value"), date:get(row,"date"), desc:get(row,"desc") };
        if(!p.title&&!p.client&&!p.projnr) continue;
        let ex=-1;
        if(p.projnr) ex=list.findIndex(x=>x.projnr&&x.projnr===p.projnr);
        if(ex>=0){ list[ex]={...list[ex],...p}; updated++; }
        else { list.push({...p,id:uid(),status:"offen",scheduledOrderId:null,ts:Date.now(),source:"taifun"}); added++; }
      }
      await persistProjects(list); setImportData(null); setView("projekte"); flash(`Import: ${added} neu, ${updated} aktualisiert.`);
      return;
    }
    let list=[...customers]; let added=0, updated=0;
    for(const row of rows){
      const cust={ kdnr:get(row,"kdnr"), name:get(row,"name"), contact:get(row,"contact"), street:get(row,"street"), zip:get(row,"zip"), city:get(row,"city"), phone:get(row,"phone"), email:get(row,"email"), notes:get(row,"notes") };
      if(!cust.name&&!cust.contact) continue;
      let ex=-1;
      if(cust.kdnr) ex=list.findIndex(c=>c.kdnr&&c.kdnr===cust.kdnr);
      if(ex<0&&cust.name) ex=list.findIndex(c=>(c.name||"").toLowerCase()===cust.name.toLowerCase()&&(c.street||"").toLowerCase()===cust.street.toLowerCase());
      if(ex>=0){ list[ex]={...list[ex],...cust}; updated++; }
      else { list.push({...cust,id:uid(),ts:Date.now(),source:"taifun"}); added++; }
    }
    await persistCustomers(list); setImportData(null); setView("kunden"); flash(`Import: ${added} neu, ${updated} aktualisiert.`);
  }

