  async function saveTime(){
    let h=parseFloat(String(timeForm.hours).replace(",","."));
    if(timeForm.von&&timeForm.bis) h=hoursBetween(timeForm.von,timeForm.bis);
    let tr=parseFloat(String(timeForm.travel||"").replace(",","."))||0;
    if(timeForm.travelVon&&timeForm.travelBis) tr=hoursBetween(timeForm.travelVon,timeForm.travelBis);
    if(!(h>0)&&!(tr>0)) return flash("Bitte Arbeitszeit oder Fahrzeit eingeben.");
    if(!timeForm.employee) return flash("Bitte Mitarbeiter wählen.");
    const entry={...timeForm,hours:Math.round((h||0)*100)/100,travel:Math.round(tr*100)/100};
    let next;
    if(timeForm.id) next=timelog.map(t=>t.id===timeForm.id?{...entry}:t);
    else next=[...timelog,{...entry,id:uid(),by:identity.name,ts:Date.now()}];
    await persistTime(next); setTimeForm(null); flash("Stunden gespeichert.");
  }
