  async function saveRapport(){
    if(!rapForm.text.trim()) return flash("Bitte die ausgeführten Arbeiten beschreiben.");
    const rid=rapForm.id||uid();
    const rap={ id:rid, date:rapForm.date, author:rapForm.author, text:rapForm.text.trim(), materials:(rapForm.materials||[]).filter(m=>(m.desc||"").trim()||(m.qty||"").toString().trim()), sig:rapForm.sig||"", signedName:(rapForm.signedName||"").trim(), ts:Date.now() };
    const oid=rapForm.orderId;
    const cur=rapports[oid]||await loadJSON("rapports:"+oid,true,[]);
    const next=rapForm.id?cur.map(r=>r.id===rid?rap:r):[...cur,rap];
    await saveJSON("rapports:"+oid,next,true);
    setRapports(s=>({...s,[oid]:next}));
    setRapForm(null); setView(rapFrom||"week"); flash("Rapport gespeichert.");
  }
