/* ===================== Import-Hilfen ===================== */
function readFileSmart(file){
  return new Promise((res,rej)=>{
    const r=new FileReader();
    r.onload=()=>{
      const buf=r.result; let text="";
      try{ text=new TextDecoder("utf-8",{fatal:false}).decode(buf); }catch{}
      if(text.indexOf("\uFFFD")>=0){ try{ text=new TextDecoder("windows-1252").decode(buf); }catch{} }
      res(text);
    };
    r.onerror=rej;
    r.readAsArrayBuffer(file);
  });
}
function parseCSV(text){
  text=text.replace(/^\uFEFF/,"");
  const nl=text.indexOf("\n"); const first=nl<0?text:text.slice(0,nl);
  const delim=(first.split(";").length>first.split(",").length)?";":",";
  const rows=[]; let row=[]; let cur=""; let inQ=false;
  for(let i=0;i<text.length;i++){
    const ch=text[i];
    if(inQ){
      if(ch==='"'){ if(text[i+1]==='"'){cur+='"';i++;} else inQ=false; }
      else cur+=ch;
    } else {
      if(ch==='"') inQ=true;
      else if(ch===delim){ row.push(cur); cur=""; }
      else if(ch==="\n"){ row.push(cur); rows.push(row); row=[]; cur=""; }
      else if(ch==="\r"){}
      else cur+=ch;
    }
  }
  if(cur!==""||row.length){ row.push(cur); rows.push(row); }
  return rows;
}
function guessMap(headers){
  const H=headers.map(h=>String(h).toLowerCase());
  const find=(...keys)=>{ for(let i=0;i<H.length;i++){ if(keys.some(k=>H[i].includes(k))) return String(i); } return "-"; };
  return {
    kdnr: find("kunden-nr","kundennummer","kd-nr","kdnr","kd.-nr","kundennr"),
    name: find("firma","name1","matchcode","name","kunde","nachname"),
    contact: find("ansprech","vorname","name2"),
    street: find("straße","strasse","str."),
    zip: find("plz","postleit"),
    city: find("ort","stadt"),
    phone: find("telefon","mobil","handy","tel"),
    email: find("mail"),
    notes: find("notiz","bemerk","info"),
  };
}

