/* ===================== Zeit-/Export-Hilfen ===================== */
function monthShift(ym,delta){ const p=ym.split("-").map(Number); const d=new Date(p[0],p[1]-1+delta,1); return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0"); }
function monthLabel(ym){ const p=ym.split("-").map(Number); return new Date(p[0],p[1]-1,1).toLocaleDateString("de-DE",{month:"long",year:"numeric"}); }
function downloadCSV(filename,rows){
  const csv=rows.map(r=>(r||[]).map(c=>{ const s=String(c==null?"":c); return /[";\n]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s; }).join(";")).join("\r\n");
  try{
    const blob=new Blob(["\uFEFF"+csv],{type:"text/csv;charset=utf-8;"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a"); a.href=url; a.download=filename; document.body.appendChild(a); a.click();
    setTimeout(()=>{ document.body.removeChild(a); URL.revokeObjectURL(url); },100);
  }catch(e){ /* ignore */ }
}

/* ===================== Unterschrift + Rapport-Anzeige ===================== */
function SignaturePad({ onChange }){
  const cref=useRef(null);
  const st=useRef({on:false,last:null,dirty:false});
  useEffect(()=>{
    const c=cref.current; if(!c) return;
    const dpr=window.devicePixelRatio||1;
    const w=c.clientWidth||300, h=180;
    c.width=w*dpr; c.height=h*dpr;
    const ctx=c.getContext("2d");
    ctx.scale(dpr,dpr); ctx.lineWidth=2.2; ctx.lineCap="round"; ctx.lineJoin="round"; ctx.strokeStyle="#1c2a3a";
  },[]);
  const pos=(e)=>{ const r=cref.current.getBoundingClientRect(); return {x:e.clientX-r.left,y:e.clientY-r.top}; };
  const down=(e)=>{ e.preventDefault(); st.current.on=true; st.current.last=pos(e); try{cref.current.setPointerCapture(e.pointerId);}catch{} };
  const move=(e)=>{ if(!st.current.on) return; e.preventDefault(); const p=pos(e); const ctx=cref.current.getContext("2d"); ctx.beginPath(); ctx.moveTo(st.current.last.x,st.current.last.y); ctx.lineTo(p.x,p.y); ctx.stroke(); st.current.last=p; st.current.dirty=true; };
  const up=()=>{ if(!st.current.on) return; st.current.on=false; if(st.current.dirty&&onChange) onChange(cref.current.toDataURL("image/png")); };
  const clear=()=>{ const c=cref.current; const ctx=c.getContext("2d"); ctx.save(); ctx.setTransform(1,0,0,1,0,0); ctx.clearRect(0,0,c.width,c.height); ctx.restore(); st.current.dirty=false; if(onChange) onChange(""); };
  return (
    <div>
      <div style={{position:"relative",border:`1px solid ${C.border}`,borderRadius:12,background:"#fff",overflow:"hidden"}}>
        <canvas ref={cref} onPointerDown={down} onPointerMove={move} onPointerUp={up} onPointerLeave={up} style={{width:"100%",height:180,display:"block",touchAction:"none",cursor:"crosshair"}}/>
        <div style={{position:"absolute",left:0,right:0,bottom:26,borderBottom:`1px dashed ${C.border}`,pointerEvents:"none"}}/>
        <div style={{position:"absolute",left:12,bottom:8,fontSize:11,color:"#B9C0B0",pointerEvents:"none"}}>Hier unterschreiben</div>
      </div>
      <button onClick={clear} style={{...chipStyle(false),padding:"6px 12px",marginTop:8}}>Unterschrift löschen</button>
    </div>
  );
}

