/* ===================== Zeitberechnung ===================== */
function hoursBetween(von,bis){
  if(!von||!bis) return 0;
  const a=von.split(":").map(Number), b=bis.split(":").map(Number);
  let d=(b[0]*60+b[1])-(a[0]*60+a[1]);
  if(d<0) d+=24*60;
  return Math.round((d/60)*100)/100;
}

/* ===================== Benachrichtigungs-Text ===================== */
function orderMsg(o){
  const p=[];
  p.push(`Neuer Auftrag: ${o.title}`);
  const day=new Date(o.date+"T00:00:00").toLocaleDateString("de-DE",{weekday:"long",day:"2-digit",month:"2-digit",year:"numeric"});
  p.push(o.from?`${day}, ${o.from}${o.to?`–${o.to}`:""} Uhr`:day);
  if(o.client) p.push(`Kunde: ${o.client}`);
  if(o.address) p.push(`Adresse: ${o.address}`);
  if(o.phone) p.push(`Tel: ${o.phone}`);
  if(o.desc) p.push(`Aufgabe: ${o.desc}`);
  p.push("— Hahn Energie & Bau");
  return p.join("\n");
}
function waNum(phone){
  let n=(phone||"").replace(/[^0-9]/g,"");
  if(n.startsWith("00")) n=n.slice(2);
  else if(n.startsWith("0")) n="49"+n.slice(1);
  return n;
}
